  1→import { useState, useEffect, useRef, useCallback } from "react";
  2→import { invoke } from "@tauri-apps/api/core";
  3→import { Sidebar } from "./features/repos/Sidebar";
  4→import { TitleBar } from "./components/TitleBar";
  5→import { TabBar } from "./components/TabBar";
  6→import { CheckpointList } from "./features/checkpoints/CheckpointList";
  7→import { TranscriptView } from "./features/transcripts/TranscriptView";
  8→import { DiffView, BranchDiffView } from "./features/diff/DiffView";
  9→import { CheckpointInsightsContainer } from "./features/insights/CheckpointInsightsContainer";
 10→import { BranchInsightsContainer } from "./features/insights/BranchInsightsContainer";
 11→import { BranchDebugContainer } from "./features/debug/BranchDebugContainer";
 12→import { CheckpointDebugContainer } from "./features/debug/CheckpointDebugContainer";
 13→import { TerminalPanel } from "./features/terminal/TerminalPanel";
 14→import type { TerminalPanelHandle } from "./features/terminal/TerminalPanel";
 15→import type { TermSession } from "./features/terminal/TerminalPanel";
 16→import { useLiveUpdates } from "./hooks/use-live-updates";
 17→import type { BranchInfo, CheckpointSummary, WorktreeInfo } from "./lib/ipc";
 18→import { ArrowLeft, GitCommit } from "lucide-react";
 19→
 20→export interface Tab {
 21→  id: string;
 22→  branch: string;
 23→  repoPath: string;
 24→  worktree: WorktreeInfo | null;
 25→  hasActiveSession: boolean;
 26→}
 27→
 28→export default function App() {
 29→  const [tabs, setTabs] = useState<Tab[]>([
 30→    {
 31→      id: "main",
 32→      branch: "main",
 33→      repoPath: "",
 34→      worktree: null,
 35→      hasActiveSession: false,
 36→    },
 37→  ]);
 38→  const [activeTabId, setActiveTabId] = useState("main");
 39→  const [terminalHeight, setTerminalHeight] = useState(
 40→    () => Number(localStorage.getItem("entire:terminal-height")) || 220
 41→  );
 42→  const [isTerminalOpen, setIsTerminalOpen] = useState(
 43→    () => localStorage.getItem("entire:terminal-open") !== "false"
 44→  );
 45→  const [innerTab, setInnerTab] = useState<
 46→    "checkpoints" | "diff" | "insights" | "debug"
 47→  >("checkpoints");
 48→  const [selectedCheckpoint, setSelectedCheckpoint] =
 49→    useState<CheckpointSummary | null>(null);
 50→  const [checkpointInnerTab, setCheckpointInnerTab] = useState<
 51→    "transcript" | "diff" | "insights" | "debug"
 52→  >("transcript");
 53→
 54→  // Per-branch terminal sessions
 55→  const [sessionMap, setSessionMap] = useState<Map<string, TermSession>>(
 56→    () => new Map()
 57→  );
 58→
 59→  const terminalRef = useRef<TerminalPanelHandle>(null);
 60→
 61→  const activeTab = tabs.find((t) => t.id === activeTabId) ?? tabs[0];
 62→  const activeSession = sessionMap.get(activeTabId) ?? null;
 63→
 64→  // Live updates — watch active repo for checkpoint/session changes
 65→  useLiveUpdates(activeTab.repoPath);
 66→
 67→  const handleSessionChange = useCallback(
 68→    (session: TermSession | null) => {
 69→      setSessionMap((prev) => {
 70→        const next = new Map(prev);
 71→        if (session) {
 72→          next.set(activeTabId, session);
 73→        } else {
 74→          next.delete(activeTabId);
 75→        }
 76→        return next;
 77→      });
 78→    },
 79→    [activeTabId]
 80→  );
 81→
 82→  // Terminal dispatch — open shell and optionally send a prompt
 83→  const handleSendToAgent = useCallback(
 84→    (_agent: string, prompt: string) => {
 85→      // Open in embedded terminal and send prompt
 86→      if (!isTerminalOpen) setIsTerminalOpen(true);
 87→      setTimeout(() => {
 88→        terminalRef.current?.launchWithPrompt(prompt);
 89→      }, isTerminalOpen ? 0 : 100);
 90→    },
 91→    [isTerminalOpen]
 92→  );
 93→
 94→  // Persist UI state to localStorage
 95→  useEffect(() => {
 96→    localStorage.setItem("entire:terminal-height", String(terminalHeight));
 97→  }, [terminalHeight]);
 98→  useEffect(() => {
 99→    localStorage.setItem("entire:terminal-open", String(isTerminalOpen));
100→  }, [isTerminalOpen]);
101→
102→  // Clear selected checkpoint when switching branch tabs
103→  useEffect(() => {
104→    setSelectedCheckpoint(null);
105→    setCheckpointInnerTab("transcript");
106→  }, [activeTabId]);
107→
108→  // Keyboard shortcuts
109→  useEffect(() => {
110→    function onKeyDown(e: KeyboardEvent) {
111→      const meta = e.metaKey || e.ctrlKey;
112→
113→      // Cmd+K = focus search
114→      if (meta && e.key === "k") {
115→        e.preventDefault();
116→        document.querySelector<HTMLInputElement>('input[placeholder*="Search"]')?.focus();
117→      }
118→      // Ctrl+` = toggle terminal
119→      if (e.ctrlKey && e.key === "`") {
120→        e.preventDefault();
121→        setIsTerminalOpen((v) => !v);
122→      }
123→      // Cmd+W = close active tab
124→      if (meta && e.key === "w") {
125→        e.preventDefault();
126→        handleCloseTab(activeTabId);
127→      }
128→      // Cmd+1-9 = switch to tab by index
129→      if (meta && e.key >= "1" && e.key <= "9") {
130→        e.preventDefault();
131→        const idx = parseInt(e.key) - 1;
132→        if (idx < tabs.length) {
133→          setActiveTabId(tabs[idx].id);
134→        }
135→      }
136→      // Cmd+[ / Cmd+] = prev/next tab
137→      if (meta && e.key === "[") {
138→        e.preventDefault();
139→        const idx = tabs.findIndex((t) => t.id === activeTabId);
140→        if (idx > 0) setActiveTabId(tabs[idx - 1].id);
141→      }
142→      if (meta && e.key === "]") {
143→        e.preventDefault();
144→        const idx = tabs.findIndex((t) => t.id === activeTabId);
145→        if (idx < tabs.length - 1) setActiveTabId(tabs[idx + 1].id);
146→      }
147→      // Escape = deselect checkpoint
148→      if (e.key === "Escape" && selectedCheckpoint) {
149→        setSelectedCheckpoint(null);
150→      }
151→    }
152→    window.addEventListener("keydown", onKeyDown);
153→    return () => window.removeEventListener("keydown", onKeyDown);
154→  }, [activeTabId, tabs, selectedCheckpoint]);
155→
156→  function handleBranchSelect(branch: BranchInfo, repoPath: string) {
157→    const existing = tabs.find(
158→      (t) => t.branch === branch.name && t.repoPath === repoPath
159→    );
160→    if (existing) {
161→      setActiveTabId(existing.id);
162→    } else {
163→      const newTab: Tab = {
164→        id: `${repoPath}:${branch.name}`,
165→        branch: branch.name,
166→        repoPath,
167→        worktree: null,
168→        hasActiveSession: false,
169→      };
170→      setTabs([...tabs, newTab]);
171→      setActiveTabId(newTab.id);
172→    }
173→  }
174→
175→  function handleWorktreeSelect(wt: WorktreeInfo, repoPath: string) {
176→    const existing = tabs.find(
177→      (t) => t.branch === wt.branch && t.repoPath === repoPath
178→    );
179→    if (existing) {
180→      setActiveTabId(existing.id);
181→    } else {
182→      const newTab: Tab = {
183→        id: `${repoPath}:${wt.branch}`,
184→        branch: wt.branch,
185→        repoPath,
186→        worktree: wt,
187→        hasActiveSession: false,
188→      };
189→      setTabs([...tabs, newTab]);
190→      setActiveTabId(newTab.id);
191→    }
192→  }
193→
194→  function handleCloseTab(tabId: string) {
195→    if (tabs.length <= 1) return;
196→    const idx = tabs.findIndex((t) => t.id === tabId);
197→    const newTabs = tabs.filter((t) => t.id !== tabId);
198→    setTabs(newTabs);
199→    if (activeTabId === tabId) {
200→      setActiveTabId(newTabs[Math.max(0, idx - 1)].id);
201→    }
202→    // Clean up ghostty surface for closed tab
203→    const closedSession = sessionMap.get(tabId);
204→    if (closedSession) {
205→      invoke("ghostty_destroy_surface", { surfaceId: closedSession.id }).catch(
206→        console.error
207→      );
208→    }
209→    setSessionMap((prev) => {
210→      const next = new Map(prev);
211→      next.delete(tabId);
212→      return next;
213→    });
214→  }
215→
216→  function handleResizeStart(e: React.MouseEvent) {
217→    e.preventDefault();
218→    const startY = e.clientY;
219→    const startHeight = terminalHeight;
220→
221→    function onMouseMove(ev: MouseEvent) {
222→      const delta = startY - ev.clientY;
223→      setTerminalHeight(Math.max(100, Math.min(600, startHeight + delta)));
224→    }
225→    function onMouseUp() {
226→      window.removeEventListener("mousemove", onMouseMove);
227→      window.removeEventListener("mouseup", onMouseUp);
228→    }
229→    window.addEventListener("mousemove", onMouseMove);
230→    window.addEventListener("mouseup", onMouseUp);
231→  }
232→
233→  const repoName = activeTab.repoPath
234→    ? activeTab.repoPath.split("/").pop()
235→    : "";
236→
237→  return (
238→    <div className="flex h-screen flex-col">
239→      <TitleBar
240→        title={`Entire — ${repoName ? `${repoName}/` : ""}${activeTab?.branch ?? ""}`}
241→      />
242→
243→      <div className="flex flex-1 overflow-hidden">
244→        {/* Sidebar */}
245→        <Sidebar
246→          activeTab={activeTab}
247→          onBranchSelect={handleBranchSelect}
248→          onWorktreeSelect={handleWorktreeSelect}
249→        />
250→
251→        {/* Main content */}
252→        <div className="flex flex-1 flex-col overflow-hidden">
253→          <TabBar
254→            tabs={tabs}
255→            activeTabId={activeTabId}
256→            onSelectTab={setActiveTabId}
257→            onCloseTab={handleCloseTab}
258→          />
259→
260→          <div className="flex flex-1 flex-col overflow-hidden">
261→            {/* Inner tabs */}
262→            <div className="flex gap-0 border-b border-border-subtle bg-bg px-5 pt-3">
263→              {(["checkpoints", "diff", "insights", "debug"] as const).map((tab) => (
264→                <button
265→                  key={tab}
266→                  onClick={() => setInnerTab(tab)}
267→                  className={`border-b-2 px-4 pb-2 text-xs font-medium capitalize transition-colors ${
268→                    innerTab === tab
269→                      ? "border-accent text-fg"
270→                      : "border-transparent text-fg-subtle hover:text-fg-muted"
271→                  }`}
272→                >
273→                  {tab === "checkpoints"
274→                    ? "Checkpoints"
275→                    : tab === "diff"
276→                      ? "Diff"
277→                      : tab === "insights"
278→                        ? "Insights"
279→                        : "Debug"}
280→                </button>
281→              ))}
282→            </div>
283→
284→            {/* Main view */}
285→            <div className="flex flex-1 overflow-hidden bg-bg">
286→              {innerTab === "checkpoints" && (
287→                <>
288→                  {/* Checkpoint list — always visible when on checkpoints tab */}
289→                  <div
290→                    className={`overflow-y-auto ${
291→                      selectedCheckpoint
292→                        ? "w-[320px] shrink-0 border-r border-border-subtle"
293→                        : "flex-1"
294→                    }`}
295→                  >
296→                    <CheckpointList
297→                      repoPath={activeTab.repoPath}
298→                      branch={activeTab.branch}
299→                      onSelectCheckpoint={(cp) => {
300→                        setSelectedCheckpoint(cp);
301→                        setCheckpointInnerTab("transcript");
302→                      }}
303→                    />
304→                  </div>
305→
306→                  {/* Checkpoint detail panel */}
307→                  {selectedCheckpoint && (
308→                    <div className="flex flex-1 flex-col overflow-hidden">
309→                      {/* Detail header */}
310→                      <div className="flex items-center gap-3 border-b border-border-subtle px-4 py-2.5">
311→                        <button
312→                          onClick={() => setSelectedCheckpoint(null)}
313→                          className="flex items-center gap-1.5 text-xs text-fg-subtle transition-colors hover:text-fg"
314→                        >
315→                          <ArrowLeft size={14} />
316→                        </button>
317→                        <GitCommit size={14} className="text-fg-subtle" />
318→                        <span className="font-mono text-xs text-accent-fg">
319→                          {selectedCheckpoint.commit_sha
320→                            ? selectedCheckpoint.commit_sha.slice(0, 7)
321→                            : selectedCheckpoint.checkpoint_id.slice(0, 7)}
322→                        </span>
323→                        <span className="truncate text-xs text-fg-muted">
324→                          {selectedCheckpoint.commit_message || "Untitled"}
325→                        </span>
326→                      </div>
327→
328→                      {/* Checkpoint sub-tabs */}
329→                      <div className="flex gap-0 border-b border-border-subtle bg-bg px-4 pt-2">
330→                        {(["transcript", "diff", "insights", "debug"] as const).map(
331→                          (tab) => (
332→                            <button
333→                              key={tab}
334→                              onClick={() => setCheckpointInnerTab(tab)}
335→                              className={`border-b-2 px-3 pb-1.5 text-[11px] font-medium capitalize transition-colors ${
336→                                checkpointInnerTab === tab
337→                                  ? "border-accent text-fg"
338→                                  : "border-transparent text-fg-subtle hover:text-fg-muted"
339→                              }`}
340→                            >
341→                              {tab === "transcript"
342→                                ? "Transcript"
343→                                : tab === "diff"
344→                                  ? "Diff"
345→                                  : tab === "insights"
346→                                    ? "Insights"
347→                                    : "Debug"}
348→                            </button>
349→                          )
350→                        )}
351→                      </div>
352→
353→                      {/* Checkpoint detail content */}
354→                      <div className="flex-1 overflow-y-auto">
355→                        {checkpointInnerTab === "transcript" && (
356→                          <TranscriptView
357→                            repoPath={activeTab.repoPath}
358→                            checkpoint={selectedCheckpoint}
359→                          />
360→                        )}
361→                        {checkpointInnerTab === "diff" && (
362→                          <DiffView
363→                            repoPath={activeTab.repoPath}
364→                            checkpoint={selectedCheckpoint}
365→                            onSendToAgent={handleSendToAgent}
366→                          />
367→                        )}
368→                        {checkpointInnerTab === "insights" && (
369→                          <CheckpointInsightsContainer
370→                            repoPath={activeTab.repoPath}
371→                            checkpoint={selectedCheckpoint}
372→                          />
373→                        )}
374→                        {checkpointInnerTab === "debug" && (
375→                          <CheckpointDebugContainer
376→                            repoPath={activeTab.repoPath}
377→                            checkpoint={selectedCheckpoint}
378→                          />
379→                        )}
380→                      </div>
381→                    </div>
382→                  )}
383→                </>
384→              )}
385→              {innerTab === "diff" && (
386→                <div className="flex flex-1 overflow-hidden">
387→                  <BranchDiffView
388→                    repoPath={activeTab.repoPath}
389→                    branch={activeTab.branch}
390→                    onSendToAgent={handleSendToAgent}
391→                  />
392→                </div>
393→              )}
394→              {innerTab === "insights" && (
395→                <div className="flex flex-1 overflow-y-auto">
396→                  <BranchInsightsContainer
397→                    repoPath={activeTab.repoPath}
398→                    branch={activeTab.branch}
399→                  />
400→                </div>
401→              )}
402→              {innerTab === "debug" && (
403→                <div className="flex flex-1 overflow-y-auto">
