import { useState, useCallback, useImperativeHandle, forwardRef } from "react";
import { invoke } from "@tauri-apps/api/core";
import { GhosttyTerminal } from "./GhosttyTerminal";
import type { Tab } from "../../App";

export interface TerminalPanelHandle {
  launchWithPrompt: (prompt: string) => Promise<void>;
}

export interface TermSession {
  id: string;
  agent: string;
  label: string;
}

interface TerminalPanelProps {
  height: number;
  tab: Tab;
  session: TermSession | null;
  onSessionChange: (session: TermSession | null) => void;
  onToggle: () => void;
}

export const TerminalPanel = forwardRef<TerminalPanelHandle, TerminalPanelProps>(
  function TerminalPanel({ height, tab, session, onSessionChange, onToggle }, ref) {
  const [isLaunching, setIsLaunching] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const launchTerminal = useCallback(
    async () => {
      if (!tab.repoPath) {
        setError("No repository selected — pick a branch from the sidebar");
        return "";
      }
      if (isLaunching) return "";

      setError(null);
      setIsLaunching(true);
      try {
        // Create a libghostty surface with the default shell (no command).
        const surfaceId: string = await invoke("ghostty_create_surface", {
          workingDir: tab.repoPath,
        });

        const newSession: TermSession = {
          id: surfaceId,
          agent: "terminal",
          label: `Terminal — ${tab.branch}`,
        };
        onSessionChange(newSession);
        return surfaceId;
      } catch (err) {
        const message = err instanceof Error ? err.message : String(err);
        console.error("Failed to create ghostty surface:", err);
        setError(`Terminal failed: ${message}`);
        return "";
      } finally {
        setIsLaunching(false);
      }
    },
    [tab.repoPath, tab.branch, isLaunching, onSessionChange]
  );

  const killSession = useCallback(async () => {
    if (!session) return;
    try {
      await invoke("ghostty_destroy_surface", { surfaceId: session.id });
    } catch (err) {
      console.error("Failed to destroy surface:", err);
    }
    onSessionChange(null);
  }, [session, onSessionChange]);

  useImperativeHandle(ref, () => ({
    async launchWithPrompt(prompt: string) {
      const surfaceId = await launchTerminal();
      if (!surfaceId) return;

      // Small delay for PTY initialization, then send the prompt
      setTimeout(async () => {
        try {
          await invoke("ghostty_send_text", {
            surfaceId,
            text: prompt + "\n",
          });
        } catch (err) {
          console.error("Failed to send prompt to terminal:", err);
        }
      }, 300);
    },
  }), [launchTerminal]);

  return (
    <div className="flex shrink-0 flex-col bg-[#0a0a0a]" style={{ height }}>
      {/* Terminal header with session info */}
      <div className="flex items-center gap-2 border-t border-border bg-bg-raised px-3 py-1.5">
        {session ? (
          <>
            <div className="flex items-center gap-1.5 rounded-md bg-accent-bg px-2.5 py-1 text-[11px] text-accent-fg">
              <span className="h-1.5 w-1.5 animate-pulse rounded-full bg-green" />
              {session.label}
            </div>
            <button
              onClick={killSession}
              className="rounded-md px-2 py-1 text-[11px] text-fg-subtle hover:bg-red/10 hover:text-red"
              title="Kill session"
            >
              ✕
            </button>
          </>
        ) : (
          <>
            <button
              onClick={() => launchTerminal()}
              disabled={isLaunching || !tab.repoPath}
              className="flex items-center gap-1.5 rounded-md border border-border-subtle px-2.5 py-1 text-[11px] text-fg-subtle transition-colors hover:border-accent hover:text-accent-fg disabled:opacity-50"
            >
              {tab.repoPath ? "+ Terminal" : "Select a repo"}
            </button>
            {error && (
              <span className="text-[11px] text-red">{error}</span>
            )}
          </>
        )}

        <button
          onClick={onToggle}
          className="ml-auto px-2 py-1 text-[11px] text-fg-subtle hover:text-fg-muted"
        >
          ⌃` Toggle ▾
        </button>
      </div>

      {/* Terminal body — transparent placeholder for native Metal overlay */}
      <div className="flex-1 overflow-hidden">
        <GhosttyTerminal surfaceId={session?.id ?? null} />
      </div>
    </div>
  );
});

use std::sync::Mutex;
use tauri::{State, WebviewWindow};

use super::overlay::{self, GhosttyOverlay};
use super::{GhosttySurface, SurfaceEntry};

fn generate_surface_id() -> String {
    use std::time::{SystemTime, UNIX_EPOCH};
    let now = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default();
    format!("ghostty-{}-{}", now.as_secs(), now.subsec_nanos())
}

/// Create a new libghostty surface with a native NSView overlay.
///
/// The surface spawns its own PTY internally. If `command` is provided
/// (e.g., "claude" or "codex"), libghostty will run that command instead
/// of the default shell.
#[tauri::command]
pub fn ghostty_create_surface(
    window: WebviewWindow,
    working_dir: String,
    command: Option<String>,
    state: State<'_, Mutex<super::GhosttyState>>,
) -> Result<String, String> {
    let mut gs = state.lock().map_err(|_| "State lock error".to_string())?;

    // Ensure the ghostty app is initialized
    gs.ensure_app()?;

    // Get the native window handle for overlay placement
    let ns_window = overlay::get_nswindow(&window)?;

    // Create the native NSView overlay
    let overlay = unsafe { GhosttyOverlay::new(ns_window)? };
    let nsview_ptr = overlay.nsview_ptr();

    // Get the window's backing scale factor for Retina displays
    let scale_factor = window.scale_factor().unwrap_or(2.0);

    // Resolve the command — map agent names to CLI binaries
    let resolved_command = command.as_deref().map(|cmd| match cmd {
        "claude-code" => "claude",
        "codex" => "codex",
        other => other,
    });

    // Create the libghostty surface
    let app = gs.app.as_ref().unwrap();
    let surface = GhosttySurface::new(
        app,
        nsview_ptr,
        Some(&working_dir),
        resolved_command,
        scale_factor,
    )?;

    let surface_id = generate_surface_id();
    gs.surfaces.insert(
        surface_id.clone(),
        SurfaceEntry { surface, overlay },
    );

    Ok(surface_id)
}

/// Destroy a surface and remove its native overlay.
#[tauri::command]
pub fn ghostty_destroy_surface(
    surface_id: String,
    state: State<'_, Mutex<super::GhosttyState>>,
) -> Result<(), String> {
    let mut gs = state.lock().map_err(|_| "State lock error".to_string())?;
    gs.surfaces.remove(&surface_id);
    // Drop handles cleanup: GhosttySurface::drop frees the libghostty surface,
    // GhosttyOverlay::drop removes the NSView from its superview.
    Ok(())
}

/// Reposition the native overlay to match the terminal panel's position in the webview.
///
/// Coordinates are in CSS pixels with top-left origin (matching getBoundingClientRect).
#[tauri::command]
pub fn ghostty_update_overlay(
    surface_id: String,
    x: f64,
    y: f64,
    width: f64,
    height: f64,
    state: State<'_, Mutex<super::GhosttyState>>,
) -> Result<(), String> {
    let gs = state.lock().map_err(|_| "State lock error".to_string())?;
    let entry = gs
        .surfaces
        .get(&surface_id)
        .ok_or_else(|| format!("Surface not found: {}", surface_id))?;

    // Update the NSView frame to match
    entry.overlay.update_frame(x, y, width, height);

    // Also update the libghostty surface size (in physical pixels for Metal)
    let scale = 2.0; // TODO: get actual scale factor
    entry
        .surface
        .set_size((width * scale) as u32, (height * scale) as u32);

    Ok(())
}

/// Show or hide the native overlay (for terminal panel toggle).
#[tauri::command]
pub fn ghostty_show_overlay(
    surface_id: String,
    visible: bool,
    state: State<'_, Mutex<super::GhosttyState>>,
) -> Result<(), String> {
    let mut gs = state.lock().map_err(|_| "State lock error".to_string())?;
    let entry = gs
        .surfaces
        .get_mut(&surface_id)
        .ok_or_else(|| format!("Surface not found: {}", surface_id))?;

    entry.overlay.set_visible(visible);
    Ok(())
}

/// Focus the native overlay so it receives keyboard input.
#[tauri::command]
pub fn ghostty_focus_overlay(
    surface_id: String,
    state: State<'_, Mutex<super::GhosttyState>>,
) -> Result<(), String> {
    let gs = state.lock().map_err(|_| "State lock error".to_string())?;
    let entry = gs
        .surfaces
        .get(&surface_id)
        .ok_or_else(|| format!("Surface not found: {}", surface_id))?;

    entry.overlay.focus();
    entry.surface.set_focus(true);
    Ok(())
}

/// Send text to the terminal surface (for agent prompt injection).
#[tauri::command]
pub fn ghostty_send_text(
    surface_id: String,
    text: String,
    state: State<'_, Mutex<super::GhosttyState>>,
) -> Result<(), String> {
    let gs = state.lock().map_err(|_| "State lock error".to_string())?;
    let entry = gs
        .surfaces
        .get(&surface_id)
        .ok_or_else(|| format!("Surface not found: {}", surface_id))?;

    entry.surface.send_text(&text);
    Ok(())
}

